const item = $input.first()?.json ?? {};
const ex = item.execution ?? {};
const wf = item.workflow ?? {};
const trg = item.trigger ?? null;
const err = ex.error ?? trg?.error ?? {};

const now = new Date();
const ts = now.toISOString();
const stamp = ts.replace(/[:.]/g, '-').slice(0, 19);
const wfName = wf.name ?? 'unknown';
const wfSlug = wfName.replace(/[^a-zA-Z0-9]+/g, '_').slice(0, 40);
const node = ex.lastNodeExecuted ?? trg?.name ?? 'n/a';
const msg = err.message ?? 'no error message';
const url = ex.url ?? 'no execution saved (activation error)';

const record = {
  ts,
  level: 'error',
  workflow: wfName,
  workflow_id: wf.id ?? null,
  execution_id: ex.id ?? null,
  node,
  mode: ex.mode ?? 'activation',
  error_name: err.name ?? null,
  message: msg,
  stack: String(err.stack ?? '').split('\n').slice(0, 6).join('\n'),
  url,
};

const filePath = $env.VEILLE_OUTPUT_DIR + '/_errors/' + stamp + '_' + wfSlug + '.json';
const content = JSON.stringify(record, null, 2);
const base64 = Buffer.from(content, 'utf-8').toString('base64');

const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const subject = '[Veille][FAIL] ' + wfName + ' — ' + node;
const html =
  '<div style="font-family:ui-monospace,monospace;font-size:13px;line-height:1.5;">' +
  '<h2 style="color:#d73a49;margin:0 0 12px;">⚠️ ' + esc(wfName) + '</h2>' +
  '<p><b>Node:</b> ' + esc(node) + '<br>' +
  '<b>Error:</b> ' + esc(msg) + '<br>' +
  '<b>Exec:</b> ' + (record.execution_id ?? 'n/a') + ' (' + record.mode + ')<br>' +
  '<b>When:</b> ' + ts + '<br>' +
  '<b>Open:</b> ' + esc(url) + '</p>' +
  '<pre style="background:#f6f8fa;padding:8px;border-radius:4px;white-space:pre-wrap;">' + esc(record.stack) + '</pre>' +
  '</div>';

return [{
  json: { filePath, to: $env.VEILLE_TO_EMAIL, subject, html, ...record },
  binary: { data: { data: base64, mimeType: 'application/json', fileName: stamp + '_' + wfSlug + '.json', fileExtension: 'json' } },
}];
